from flask import Flask, request, redirect, url_for, render_template_string
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy database for demonstration purposes
users_db = {
    'user1@example.com': {'mfa_enabled': False}
}

def send_reset_link(email):
    reset_token = secrets.token_urlsafe()
    users_db[email]['reset_token'] = reset_token
    reset_url = url_for('reset_mfa', token=reset_token, _external=True)
    msg = MIMEText(f'Click the link to reset MFA: {reset_url}')
    msg['Subject'] = 'MFA Reset Link'
    msg['From'] = 'your_email@example.com'
    msg['To'] = email
    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your_email@example.com', 'your_password')
        server.sendmail('your_email@example.com', email, msg.as_string())

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.form['email']
    if email in users_db:
        users_db[email]['mfa_enabled'] = True
        return 'MFA enabled successfully'
    else:
        return 'User not found', 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.form['email']
    if email in users_db:
        users_db[email]['mfa_enabled'] = False
        return 'MFA disabled successfully'
    else:
        return 'User not found', 404

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa(token):
    for user_email, user_info in users_db.items():
        if user_info.get('reset_token') == token:
            user_info['mfa_enabled'] = False
            del user_info['reset_token']
            return 'MFA reset successfully. Please log in with your password.'
    return 'Invalid reset link', 400

@app.route('/send-reset-link', methods=['POST'])
def send_reset_link_route():
    email = request.form['email']
    if email in users_db:
        send_reset_link(email)
        return 'Reset link sent successfully'
    else:
        return 'User not found', 404

if __name__ == '__main__':
    app.run(debug=True)